import { useState } from "react";
import { s } from "./LoginPage.styles";
const BG_IMAGE = "https://www.figma.com/api/mcp/asset/c5e43914-c60a-4913-9aee-2d22bd1551d8";



export default function LoginPage({ onNavigate }) {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

  return (
    <div style={s.page}>
      <style>{`@import url('https://fonts.googleapis.com/css2?family=Libre+Bodoni:wght@400;700&display=swap');`}</style>

      {/* Left — salon photo */}
      <div style={s.left} />

      {/* Right — form */}
      <div style={s.right}>
        {/* Back to website */}
        <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 60, cursor: "pointer" }}
          onClick={() => onNavigate("home")}>
          <span style={{ fontSize: 20, color: "#5f4a28" }}>◀</span>
          <span style={{ fontSize: 20, color: "#5f4a28", fontWeight: 400 }}>Back to website</span>
        </div>

        <h1 style={s.title}>Welcome back!</h1>
        <p style={s.subtitle}>Log in to get started with Glow &amp; Shine</p>
        <p style={s.tagline}>Timeless Beauty, Modern Touch</p>

        <label style={s.label}>Email</label>
        <input
          style={s.input}
          type="email"
          placeholder="abc123@gmail.com"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
        />

        <label style={s.label}>Password</label>
        <input
          style={s.input}
          type="password"
          placeholder="••••••••"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
        />
        <p style={s.hint}>
          Password must contain at least 8 characters, one uppercase letter, one number and one special character
        </p>

        <button style={s.loginBtn} onClick={() => onNavigate("services")}>
          Log in
        </button>

        <div style={s.forgotRow}>
          <span style={s.forgot}>Forgot password?</span>
        </div>

        <p style={s.signupRow}>
          Don't you have an account?{" "}
          <span style={s.signupLink} onClick={() => onNavigate("signup")}>Sign up</span>
        </p>
      </div>
    </div>
  );
}
